import anthropic, time, random

client = anthropic.Anthropic()

def create_with_retry(messages: list, max_retries: int = 4) -> anthropic.types.Message:
    for attempt in range(max_retries + 1):
        try:
            return client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=1024,
                messages=messages
            )
        except anthropic.RateLimitError:
            if attempt == max_retries:
                raise
            delay = (2 ** attempt) + random.uniform(0, 1)
            print(f"Rate limited. Retrying in {delay:.1f}s (attempt {attempt + 1})")
            time.sleep(delay)
        except anthropic.APIStatusError as e:
            if e.status_code in (500, 529) and attempt < max_retries:
                delay = (2 ** attempt) + random.uniform(0, 1)
                print(f"Server error {e.status_code}. Retrying in {delay:.1f}s")
                time.sleep(delay)
            else:
                raise

# Create a batch
batch = client.messages.batches.create(
    requests=[
        {
            "custom_id": f"task-{i}",
            "params": {
                "model": "claude-haiku-4-5-20251001",
                "max_tokens": 512,
                "messages": [{"role": "user", "content": prompt}]
            }
        }
        for i, prompt in enumerate(prompts)
    ]
)
print(f"Batch ID: {batch.id} - status: {batch.processing_status}")

# Poll until complete (use webhook or cron job in production)
import time
while batch.processing_status == "in_progress":
    time.sleep(60)
    batch = client.messages.batches.retrieve(batch.id)

# Stream results
for result in client.messages.batches.results(batch.id):
    if result.result.type == "succeeded":
        print(f"{result.custom_id}: {result.result.message.content[0].text[:100]}")
    else:
        print(f"{result.custom_id}: ERRORED - {result.result.error}")
